(window.webpackJsonp=window.webpackJsonp||[]).push([[308],{935:function(n,t){n.exports='\x3c!-- \ntitle: 02-Vue进阶\nsort: \n--\x3e \n\n## 指令\n\n> `v-model`\n\n```js\n// 单选\n<label>\n  ♂ <input v-model="sex" value="male" type="radio">\n  ♀ <input v-model="sex" value="female" type="radio">\n</label>\n\ndata:{\n  sex: "female",\n},\n  \n// 多选 类型修改，data变成数组\ntype="checkbox"\ndata:{\n  sex: []\n},\n \n// 文本输入框\n<textarea v-model="article"></textarea>\n  \n// select\n<select v-model="from">\n  <option value="1">*黑龙江</option>\n  <option value="2">*吉林</option>\n  <option value="3">*辽宁</option>\n</select>\n<p>您来自：{{from}}号疫情区</p>\n  \ndata:{\n  from:1\n}\n```\n\n## 计算属性\n\n```js\n<table border="1">\n  <thead>\n    <th>学科</th>\n    <th>分数</th>\n  </thead>\n  <tbody>\n    <tr>\n      <td>数学</td>\n      <td><input type="text" v-model.number="math"></td>\n    </tr>\n    <tr>\n      <td>英语</td>\n      <td><input type="text" v-model.number="english"></td>\n    </tr>\n    <tr>\n      <td>平均分</td>\n      <td>{{average}}</td>\n    </tr>\n    <tr>\n      <td>总分</td>\n      <td>{{sum}}</td>\n    </tr>\n  </tbody>\n</table>\n\ndata: {\n  math: 98,\n  english: 35,\n},\ncomputed: {\n  sum: function () {\n    return this.math + this.english\n  },\n  average: function () {\n    return (this.sum)/2\n  }\n}\n```\n\n'}}]);